// ══════════════════════════════════════════════════════════════════════
// 🔧  Post-Contact-Merge Resolver
//
//  After Merge2, some items arrive from the TRUE branch (contact_found=true,
//  partner_id already populated) and some from Create an CONTACT2 (new ID).
//  This node normalises both paths into a single `resolved_partner_id`.
// ══════════════════════════════════════════════════════════════════════
return $input.all().map(item => {
  const d = item.json;

  // If the item came through the FALSE branch, Create an CONTACT2
  // stored the new Odoo ID in d.id (Odoo create response).
  // The original Super Transformer data is in d (all fields were merged).
  const resolved_partner_id =
    d.partner_id                    // already existed
    ?? d.id                         // freshly created (Odoo returns { id: N })
    ?? null;

  return {
    json: {
      ...d,
      resolved_partner_id,
    }
  };
});

// ══════════════════════════════════════════════════════════════════════
// 🔧  Pre-Payment Builder
//
//  Merges the journal lookup result back into the collection data.
//  Get Journal outputs { id, name, ... } but loses the original item.
//  We re-attach everything needed for Create an PAYMENT2.
// ══════════════════════════════════════════════════════════════════════
return $input.all().map((item, idx) => {
  const journal = item.json;   // output of Get Journal

  // Re-fetch the corresponding Super Transformer data via index
  // (items are 1-to-1 because Get Journal processes one item at a time)
  const src = $('Resolve Partner ID').item?.json ?? {};

  const journal_id = journal.id ?? null;

  return {
    json: {
      ...src,
      journal_odoo_id : journal_id,
      journal_name    : journal.name ?? src.odoo_journal_name,
    }
  };
});

// 1. جلب بيانات أودو من السهم اللي جاي من Get many items2
const partners = $( "Get many items2" ).all().map(i => i.json);

// 2. جلب التحصيلات من السهم اللي جاي من Split Out
const collections = $( "Split Out4" ).all();

// 3. التنفيذ بناءً على عدد التحصيلات فقط
return collections.map(item => {
    const data = item.json;

    // وظيفة التنظيف للمطابقة المرنة (Shedhel vs Sedhel)
    const clean = (str) => str ? str.toLowerCase().replace(/\s+/g, '').replace(/sh/g, 's').trim() : "";

    let isShipping = (data.collection_type === "شحن");
    let targetName = isShipping 
        ? `عملاء نقدي ${data.project_name || ''}`.trim() 
        : (data.owner_name || "").trim();

    // البحث في الـ 198 عميل اللي جبناهم
    let foundPartner = partners.find(p => clean(p.name) === clean(targetName));

    // القرار: شحن ميكريتش أبداً - عام يكريت لو مش موجود
    const shouldCreate = (data.collection_type !== "شحن" && !foundPartner);

    return {
        json: {
            ...data,
            odoo_partner_name: targetName,
            partner_id: foundPartner ? foundPartner.id : null,
            contact_found: !!foundPartner,
            should_create_contact: shouldCreate,

            // معالجة البنك والميمو
            odoo_payment_label: (data.payment_method || "").split('(')[0].trim(),
            odoo_journal_name: data.payment_method?.match(/\(([^)]+)\)/)?.[1] || "Cash",
            odoo_memo: `Type: ${data.collection_type} | ID: ${data.id}`,
            odoo_amount: parseFloat(data.total_amount) || 0,
            odoo_date: data.collection_time ? data.collection_time.split(' ')[0] : ""
        }
    };
});

// ══════════════════════════════════════════════════════════════════════
// 🖼️  Image Downloader
//    Downloads receipt image and converts to base64 for Odoo attachment.
//    Handles both receipt_image and receipt_image_url field names.
// ══════════════════════════════════════════════════════════════════════
const results = [];

for (const item of $input.all()) {
  const raw      = item.json;
  const imageUrl = (raw.receipt_image ?? raw.receipt_image_url ?? '').trim();

  if (!imageUrl) {
    results.push({ json: { ...raw, image_base64: null, image_fetched: false } });
    continue;
  }

  try {
    const resp = await this.helpers.httpRequest({
      method  : 'GET',
      url     : imageUrl,
      encoding: 'arraybuffer',
    });
    const base64 = Buffer.from(resp).toString('base64');
    results.push({ json: { ...raw, image_base64: base64, image_fetched: true } });
  } catch (err) {
    results.push({ json: {
      ...raw,
      image_base64 : null,
      image_fetched: false,
      image_error  : err.message,
    }});
  }
}

return results;

// ══════════════════════════════════════════════════════════════════════
// 📎  Prepare Attachment Data
//    Extracts only what's needed for ir.attachment creation.
// ══════════════════════════════════════════════════════════════════════
return $input.all().map(item => {
  const d = item.json;
  return {
    json: {
      collection_id   : d.id              ?? d.collection_id,
      payment_odoo_id : d.payment_id      ?? d.id,
      image_base64    : d.image_base64    ?? null,
      image_fetched   : d.image_fetched   ?? false,
    }
  };
});

