// ══════════════════════════════════════════════════════════════════════
// 🧠  Super Transformer — Collections → Odoo Normaliser  (v4.1 FINAL)
//  INPUT  ← Split Out5       (portal collections, N items)
//  INPUT  ← Get many items3  (Odoo res.partner, 198 items, executeOnce)
//  OUTPUT → exactly N items, one per collection
// ══════════════════════════════════════════════════════════════════════

/* ── 0.  Loop-isolation: pull both datasets via $() ─────────────────── */
const partnerNode    = $('Get many items');
const collectionNode = $('Split Out');

if (!partnerNode || !collectionNode) {
  throw new Error(
    'Super Transformer: missing upstream node reference. ' +
    'Ensure "Get many items3" and "Split Out5" are connected.'
  );
}

const partners    = partnerNode.all().map(i => i.json);
const collections = collectionNode.all().map(i => i.json);

/* ── 1.  Project-name map (API English → Odoo Arabic) ──────────────── */
const PROJECT_NAME_MAP = {
  'Ein Bay'     : 'العين باي',
  'Seychelles'  : 'سيشل',
  'Sedhel'      : 'السديل',
  'Shedhel'     : 'السديل',
  'Pharma Beach': 'فارما بيتش',
};

/* ── 2.  Fuzzy-cleaning helper ─────────────────────────────────────── */
function clean(str) {
  if (!str) return '';
  return String(str)
    .toLowerCase()
    .replace(/\s+/g, '')                           // spaces
    .replace(/sh/g, 's')                            // sh → s
    .replace(/[\u064B-\u065F\u0670\u0640]/g, '')   // tashkeel
    .replace(/[إأآا]/g, 'ا')                        // alef variants
    .replace(/ى/g, 'ي')                             // alef maksura → ya
    .replace(/ة/g, 'ه');                            // ta marbuta → ha
}

/* ── 3.  Resolve the Odoo contact name we expect to find ───────────── */
function resolveTargetName(data) {
  const type       = (data.collection_type || '').trim();
  const rawProject = (data.project_name    || '').trim();
  const owner      = (data.owner_name      || '').trim();
  if (type === 'شحن') {
    const mapped = PROJECT_NAME_MAP[rawProject] || rawProject;
    return `عملاء نقدي ${mapped}`.trim();
  }
  return owner;
}

/* ── 4.  Extract bank / journal name from payment_method ───────────── */
function extractJournalName(paymentMethod) {
  if (!paymentMethod) return 'Cash';
  const m = paymentMethod.match(/\(([^)]+)\)/);
  return m ? m[1].trim() : paymentMethod.trim();
}

/* ── 5.  Main transform: 1 output item per collection ──────────────── */
return collections.map((item, idx) => {
  const targetName  = resolveTargetName(item);
  const targetClean = clean(targetName);

  // Fuzzy partner search
  let foundPartner = partners.find(p => clean(p.name) === targetClean);

  // Fallback: substring containment (cleaned)
  if (!foundPartner) {
    foundPartner = partners.find(p => {
      const pc = clean(p.name);
      return pc.includes(targetClean) || targetClean.includes(pc);
    });
  }

  const isShipping   = (item.collection_type === 'شحن');
  const shouldCreate = !isShipping && !foundPartner;

  const memo = `Type: ${item.collection_type || 'N/A'} | ID: ${item.id ?? 'N/A'}`;
  const odooDate = item.collection_time ? item.collection_time.split(' ')[0] : '';

  return {
    json: {
      ...item,
      _transform_index: idx,
      odoo_partner_name: targetName,
      partner_id: foundPartner ? foundPartner.id : null,
      contact_found: !!foundPartner,
      should_create_contact: shouldCreate,
      odoo_payment_label: (item.payment_method || '').split('(')[0].trim(),
      odoo_journal_name: extractJournalName(item.payment_method),
      odoo_memo: memo,
      odoo_amount: parseFloat(item.total_amount) || 0,
      odoo_date: odooDate,
    }
  };
});

