const merged = $input.all();
const originals = $('Super Transformer2').all();

return merged.map((item, idx) => {
  const d = item.json;
  const orig = originals[idx]?.json || {};

  // الـ ID الصح: إما موجود مسبقاً (partner_id) أو جديد (id من Create Contact)
  const resolved_partner_id = d.partner_id ?? d.id ?? null;

