/* ── 4.  Journal ID Mapping (CIB=27, Alex=28, AAIB=30, Fawaterk=32) ── */
const JOURNAL_ID_MAP = {
  'cib': 27,
  'التجاري الدولي': 27,
  'الإسكندرية': 28,
  'الاسكندرية': 28,
  'alex bank': 28,
  'العربي الأفريقي': 30,
  'العربي الافريقي': 30,
  'aaib': 30,
  // إضافة فواتيرك بالـ ID الجديد
  'fawaterk': 32,
  'فواتيرك': 32,
};

function resolveJournalId(paymentMethod) {
  if (!paymentMethod) return 24; // الـ Fallback بقى 24 (الكاش) بدل 7
  const pm = paymentMethod.toLowerCase();

  // 1. البحث المباشر في الخريطة
  for (const [key, id] of Object.entries(JOURNAL_ID_MAP)) {
    if (pm.includes(key.toLowerCase())) return id;
  }

  // 2. البحث داخل الأقواس لو موجودة (مثلاً انستاباي (CIB))
  const bracketMatch = pm.match(/\(([^)]+)\)/);
  if (bracketMatch) {
    const inside = bracketMatch[1].toLowerCase();
    for (const [key, id] of Object.entries(JOURNAL_ID_MAP)) {
      if (inside.includes(key.toLowerCase())) return id;
    }
  }

  return 24; // أي حاجة تانية تروح للخزنة الرئيسية (ID 24)
}

